"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[165633],{525975:e=>{e.exports=JSON.parse('{"tag":{"label":"weapon","permalink":"/dst-api-webdocs/docs/tags/weapon","allTagsPath":"/dst-api-webdocs/docs/tags","count":38,"items":[{"id":"game-scripts/components/aoeweapon_leap","title":"Aoeweapon Leap","description":"Enables a leap-based area-of-effect weapon attack that hits multiple targets in a radius and optionally tosses physics-enabled entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/aoeweapon_leap"},{"id":"game-scripts/prefabs/axe_pickaxe","title":"Axe Pickaxe","description":"A multitool item that functions as both an axe and a pickaxe, with limited durability and weapon capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/axe_pickaxe"},{"id":"game-scripts/prefabs/batbat","title":"Batbat","description":"A consumable weapon item that deals damage on attack and drains health/sanity from valid targets on critical hits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/batbat"},{"id":"game-scripts/prefabs/blowdart_lava","title":"Blowdart Lava","description":"A specialized blowdart item that launches explosive lava projectiles, using AOE targeting with custom reticule behavior and visual trails.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart_lava"},{"id":"game-scripts/prefabs/blowdart_lava2","title":"Blowdart Lava2","description":"A lava arena-specific blowdart weapon prefab that uses reticule-based targeting and spawns distinct projectile types with visual tail effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart_lava2"},{"id":"game-scripts/prefabs/boomerang","title":"Boomerang","description":"A reusable ranged weapon that returns to the thrower after hitting a target or missing, with finite durability and equippable state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boomerang"},{"id":"game-scripts/prefabs/bugnet","title":"Bugnet","description":"A reusable tool-and-weapon item that captures insects and degrades after a fixed number of uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bugnet"},{"id":"game-scripts/prefabs/cane_sharp_fx","title":"Cane Sharp Fx","description":"Creates a visual effect particle system used for the cane sharp weapon\'s glowing trail.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cane_sharp_fx"},{"id":"game-scripts/prefabs/cutless","title":"Cutless","description":"A wearable weapon that deals damage and steals items from targets on attack.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutless"},{"id":"game-scripts/prefabs/flamethrower_fx","title":"Flamethrower Fx","description":"Spawns and manages flame-effect entities for the flamethrower weapon\'s area-of-effect damage in Warg\'s mutated attack.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flamethrower_fx"},{"id":"game-scripts/prefabs/glasscutter","title":"Glasscutter","description":"A consumable weapon prefab that deals damage with finite uses, deals bonus damage against shadow enemies, and provides visual feedback via equipped animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glasscutter"},{"id":"game-scripts/prefabs/hambat","title":"Hambat","description":"A perishable melee weapon whose damage decreases as it spoils over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hambat"},{"id":"game-scripts/prefabs/hammer_mjolnir","title":"Hammer Mjolnir","description":"Defines the Hammer Mjolnir weapon prefab and associated FX prefabs for the Lava Arena event, including reticule targeting and area-of-effect capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hammer_mjolnir"},{"id":"game-scripts/prefabs/houndstooth_blowpipe","title":"Houndstooth Blowpipe","description":"A ranged weapon that fires houndstooth darts; manages ammo loading/unloading, equipping animations, and projectile behavior including visual tail effects and impact spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/houndstooth_blowpipe"},{"id":"game-scripts/prefabs/lavaarena_firebomb","title":"Lavaarena Firebomb","description":"Provides a throwable weapon for the Lava Arena event that projects an AOE targeting reticule and fires projectiles on use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_firebomb"},{"id":"game-scripts/prefabs/lavaarena_heavyblade","title":"Lavaarena Heavyblade","description":"A weapon prefab that implements area-of-effect targeting with an arc-shaped reticule for precision targeting in lava arena combat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_heavyblade"},{"id":"game-scripts/prefabs/lavaarena_lucy","title":"Lavaarena Lucy","description":"Provides the weapon entity for Lucy\'s spinning axe attack in the Lava Arena, handling reticule targeting and visual feedback.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_lucy"},{"id":"game-scripts/prefabs/mosquitobomb","title":"Mosquitobomb","description":"A throwable weapon that explodes on impact to spawn temporary mosquito followers and deal area damage to enemies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitobomb"},{"id":"game-scripts/prefabs/nightstick","title":"Nightstick","description":"A renewable light source weapon that ignites on equip and deactivates when unequipped or pocketed; supports battery and moonspark charging.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightstick"},{"id":"game-scripts/prefabs/nightsword","title":"Nightsword","description":"A consumable weapon that deals shadow damage and loses one use each time it is swung.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword"},{"id":"game-scripts/prefabs/nightsword_lightsbane_fx","title":"Nightsword Lightsbane Fx","description":"Creates and manages particle effects for the Nightsword Lightsbane weapon attack animation on the client.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword_lightsbane_fx"},{"id":"game-scripts/prefabs/nightsword_sharp_fx","title":"Nightsword Sharp Fx","description":"Spawns particle effects synchronized with weapon attack animations for the Nightsword, emitting smoke, sparks, and embers during combat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword_sharp_fx"},{"id":"game-scripts/components/parryweapon","title":"Parryweapon","description":"Provides parry detection logic and event hooks for combat weapons, validating whether an attack can be successfully parried based on angular alignment and stimuli type.","permalink":"/dst-api-webdocs/docs/game-scripts/components/parryweapon"},{"id":"game-scripts/prefabs/pickaxe","title":"Pickaxe","description":"A tool-and-weapon prefab providing mining and combat functionality with finite durability, equipped with visual, inventory, and network support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pickaxe"},{"id":"game-scripts/prefabs/pickaxe_lunarplant","title":"Pickaxe Lunarplant","description":"A specialized mining tool that gains increased damage when equipped alongside the Lunar Plant Hat, with separate states for intact and broken conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pickaxe_lunarplant"},{"id":"game-scripts/prefabs/pocketwatch_weapon_fx","title":"Pocketwatch Weapon Fx","description":"Spawns a particle effect for the pocketwatch weapon\u2019s attack animation, emitting rotating sparkles with animated UVs and dynamic emission rates based on the owner\u2019s state and movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketwatch_weapon_fx"},{"id":"game-scripts/prefabs/shadow_battleaxe","title":"Shadow Battleaxe","description":"A leveled, sentient weapon that evolves through epic creature kills, providing life steal, planar damage, and dynamic chat behavior while requiring hunger management and durability tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_battleaxe"},{"id":"game-scripts/prefabs/shadow_battleaxe_classified","title":"Shadow Battleaxe Classified","description":"Provides classified talk logic for the Shadow Battleaxe weapon, managing string playback and sound synchronization when the weapon is held by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_battleaxe_classified"},{"id":"game-scripts/prefabs/shovel","title":"Shovel","description":"Implements the shovel and golden shovel prefabs with dig capability, limited durability, weapon damage, and equip/unequip animation handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel"},{"id":"game-scripts/prefabs/shovel_lunarplant","title":"Shovel Lunarplant","description":"A lunar plant\u2013themed shovel that grants bonus damage and planar damage when equipped alongside a Lunar Plant Hat, with dynamic behavior based on breakage state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel_lunarplant"},{"id":"game-scripts/prefabs/slingshot","title":"Slingshot","description":"Manages the core functionality, visual layers, equipment, and projectile launching behavior for the slingshot weapon and its variants in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshot"},{"id":"game-scripts/prefabs/spear_gungnir","title":"Spear Gungnir","description":"A specialized ranged weapon prefabs with reticule-based targeting, designed for the Lava Arena event, featuring lunge-based attacks and visual effects integration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear_gungnir"},{"id":"game-scripts/prefabs/spear_lance","title":"Spear Lance","description":"A combat weapon prefab that enables area-of-effect leap attacks with reticule-guided targeting and recharge functionality.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear_lance"},{"id":"game-scripts/prefabs/tentaclespike","title":"Tentaclespike","description":"A consumable weapon item that deals damage and degrades after a fixed number of uses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tentaclespike"},{"id":"game-scripts/prefabs/trident","title":"Trident","description":"A magical trident that enables\u8fdc\u7a0b wave-spawned explosions on water and interacts with fish, plants, and structures in the ocean.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trident"},{"id":"game-scripts/prefabs/waterplant_seed","title":"Waterplant Seed","description":"Represents a throwable bomb item that explodes on impact, damaging nearby targets and damaging boats if no combat target is hit.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterplant_seed"},{"id":"game-scripts/prefabs/whip","title":"Whip","description":"A ranged combat item that attacks targets with a whip, triggering knockback effects and optional supersnap mechanics against enemies with active combat targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/whip"},{"id":"game-scripts/prefabs/yoth_lance","title":"Yoth Lance","description":"A consumable ranged weapon component that provides melee combat functionality with lance-specific jousting mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yoth_lance"}],"unlisted":false}}')}}]);